"""
Test Suite: Employee Onboarding Document Upload
Requirement: Employees shall upload onboarding documents up to 10MB in PDF, PNG, or JPG format.
             Files outside this specification must be rejected.
             A webhook event must be emitted for external consumers on successful upload.
"""

import io
import json
import pytest
from unittest.mock import MagicMock, patch, call
from http import HTTPStatus


# ---------------------------------------------------------------------------
# Constants (mirror what the production code should enforce)
# ---------------------------------------------------------------------------
MAX_FILE_SIZE_BYTES = 10 * 1024 * 1024          # 10 MB
ALLOWED_MIME_TYPES = {"application/pdf", "image/png", "image/jpeg"}
ALLOWED_EXTENSIONS = {".pdf", ".png", ".jpg", ".jpeg"}
WEBHOOK_EVENT_NAME = "onboarding.document.uploaded"


# ---------------------------------------------------------------------------
# Helpers / Fixtures
# ---------------------------------------------------------------------------

def make_file(
    filename: str = "document.pdf",
    mime_type: str = "application/pdf",
    size_bytes: int = 1 * 1024 * 1024,   # 1 MB default
) -> MagicMock:
    """Return a mock file object that mimics an uploaded file."""
    mock_file = MagicMock()
    mock_file.filename = filename
    mock_file.content_type = mime_type
    mock_file.read.return_value = b"0" * size_bytes
    mock_file.seek.return_value = None
    # Allow len() via __len__ and size attribute
    mock_file.__len__ = lambda self: size_bytes
    mock_file.size = size_bytes
    return mock_file


@pytest.fixture
def valid_pdf():
    return make_file("resume.pdf", "application/pdf", 2 * 1024 * 1024)


@pytest.fixture
def valid_png():
    return make_file("photo.png", "image/png", 500 * 1024)


@pytest.fixture
def valid_jpg():
    return make_file("id_card.jpg", "image/jpeg", 1 * 1024 * 1024)


@pytest.fixture
def valid_jpg_jpeg_extension():
    """Some clients send .jpeg instead of .jpg — both must be accepted."""
    return make_file("id_card.jpeg", "image/jpeg", 1 * 1024 * 1024)


@pytest.fixture
def file_at_exact_limit():
    return make_file("big.pdf", "application/pdf", MAX_FILE_SIZE_BYTES)


@pytest.fixture
def file_one_byte_over_limit():
    return make_file("too_big.pdf", "application/pdf", MAX_FILE_SIZE_BYTES + 1)


@pytest.fixture
def file_empty():
    return make_file("empty.pdf", "application/pdf", 0)


@pytest.fixture
def file_wrong_extension():
    return make_file("spreadsheet.xlsx", "application/vnd.ms-excel", 1 * 1024 * 1024)


@pytest.fixture
def file_wrong_mime_type():
    """Correct extension but wrong MIME type — must be rejected."""
    return make_file("malicious.pdf", "application/octet-stream", 1 * 1024 * 1024)


@pytest.fixture
def file_spoofed_extension():
    """Executable renamed to .pdf — MIME type betrays it."""
    return make_file("virus.pdf", "application/x-msdownload", 1 * 1024 * 1024)


@pytest.fixture
def mock_webhook_client():
    with patch("onboarding.webhooks.WebhookClient") as MockClient:
        instance = MockClient.return_value
        instance.send.return_value = MagicMock(status_code=200)
        yield instance


@pytest.fixture
def mock_storage():
    with patch("onboarding.storage.DocumentStorage") as MockStorage:
        instance = MockStorage.return_value
        instance.save.return_value = {"document_id": "doc-abc-123", "url": "https://storage.example.com/doc-abc-123"}
        yield instance


@pytest.fixture
def upload_service(mock_storage, mock_webhook_client):
    """
    Provides an UploadService wired with mocked storage and webhook dependencies.
    Adjust the import path to match your project layout.
    """
    from onboarding.services import DocumentUploadService
    return DocumentUploadService(storage=mock_storage, webhook_client=mock_webhook_client)


# ---------------------------------------------------------------------------
# 1. Accepted File Types
# ---------------------------------------------------------------------------

class TestAcceptedFileTypes:

    def test_upload_pdf_is_accepted(self, upload_service, valid_pdf):
        result = upload_service.upload(employee_id="emp-001", file=valid_pdf)
        assert result["success"] is True

    def test_upload_png_is_accepted(self, upload_service, valid_png):
        result = upload_service.upload(employee_id="emp-001", file=valid_png)
        assert result["success"] is True

    def test_upload_jpg_is_accepted(self, upload_service, valid_jpg):
        result = upload_service.upload(employee_id="emp-001", file=valid_jpg)
        assert result["success"] is True

    def test_upload_jpeg_extension_is_accepted(self, upload_service, valid_jpg_jpeg_extension):
        result = upload_service.upload(employee_id="emp-001", file=valid_jpg_jpeg_extension)
        assert result["success"] is True

    @pytest.mark.parametrize("filename, mime", [
        ("doc.xlsx",  "application/vnd.ms-excel"),
        ("doc.docx",  "application/vnd.openxmlformats-officedocument.wordprocessingml.document"),
        ("doc.txt",   "text/plain"),
        ("doc.gif",   "image/gif"),
        ("doc.bmp",   "image/bmp"),
        ("doc.mp4",   "video/mp4"),
        ("doc.zip",   "application/zip"),
