            upload_service.upload(employee_id="emp-001", file=file_wrong_extension)
        assert "xlsx" in str(exc_info.value).lower() or "unsupported" in str(exc_info.value).lower()

    def test_rejection_error_includes_size_limit_info(self, upload_service, file_one_byte_over_limit):
        with pytest.raises(ValueError) as exc_info:
            upload_service.upload(employee_id="emp-001", file=file_one_byte_over_limit)
        assert "10" in str(exc_info.value)   # limit mentioned in message

    def test_rejection_does_not_return_success(self, upload_service, file_wrong_extension):
        with pytest.raises(ValueError):
            result = upload_service.upload(employee_id="emp-001", file=file_wrong_extension)
            assert result.get("success") is not True


