# 4. Successful Upload Response
# ---------------------------------------------------------------------------

class TestSuccessfulUploadResponse:

    def test_successful_upload_returns_document_id(self, upload_service, valid_pdf):
        result = upload_service.upload(employee_id="emp-001", file=valid_pdf)
        assert "document_id" in result

    def test_successful_upload_returns_success_flag(self, upload_service, valid_pdf):
        result = upload_service.upload(employee_id="emp-001", file=valid_pdf)
        assert result["success"] is True

    def test_successful_upload_returns_document_url(self, upload_service, valid_pdf):
        result = upload_service.upload(employee_id="emp-001", file=valid_pdf)
        assert "url" in result
        assert result["url"].startswith("https://")

    def test_successful_upload_returns_employee_id(self, upload_service, valid_pdf):
