        mock_webhook_client.send.assert_called_once()

    def test_webhook_event_name_is_correct(
        self, upload_service, mock_webhook_client, valid_pdf
    ):
        upload_service.upload(employee_id="emp-001", file=valid_pdf)
        _, kwargs = mock_webhook_client.send.call_args
        payload = kwargs.get("payload") or mock_webhook_client.send.call_args[0][0]
        assert payload["event"] == WEBHOOK_EVENT_NAME

    def test_webhook_payload_contains_employee_id(
        self, upload_service, mock_webhook_client, valid_pdf
    ):
        upload_service.upload(employee_id="emp-001", file=valid_pdf)
        args, kwargs = mock_webhook_client.send.call_args
        payload = kwargs.get("payload", args[0] if args else {})
        assert payload["employee_id"] == "emp-001"

    def test_webhook_payload_contains_document_id(
        self, upload_service, mock_webhook_client, valid_pdf
    ):
        upload_service.upload(employee_id="emp-001", file=valid_pdf)
        args, kwargs = mock_webhook_client.send.call_args
        payload = kwargs.get("payload", args[0] if args else {})
        assert "document_id" in payload

    def test_webhook_payload_contains_filename(
        self, upload_service, mock_webhook_client, valid_pdf
    ):
        upload_service.upload(employee_id="emp-001", file=valid_pdf)
        args, kwargs = mock_webhook_client.send.call_args
        payload = kwargs.get("payload", args[0] if args else {})
        assert payload.get("filename") == valid_pdf.filename

    def test_webhook_payload_contains_mime_type(
        self, upload_service, mock_webhook_client, valid_pdf
    ):
        upload_service.upload(employee_id="emp-001", file=valid_pdf)
        args, kwargs = mock_webhook_client.send.call_args
        payload = kwargs.get("payload", args[0] if args else {})
        assert payload.get("mime_type") == "application/pdf"

    def test_webhook_payload_contains_file_size(
        self, upload_service, mock_webhook_client, valid_pdf
    ):
        upload_service.upload(employee_id="emp-001", file=valid_pdf)
        args, kwargs = mock_webhook_client.send.call_args
        payload = kwargs.get("payload", args[0] if args else {})
        assert "file_size_bytes" in payload
        assert payload["file_size_bytes"] == valid_pdf.size

    def test_webhook_payload_contains_timestamp(
        self, upload_service, mock_webhook_client, valid_pdf
    ):
        upload_service.upload(employee_id="emp-001", file=valid_pdf)
        args, kwargs = mock_webhook_client.send.call_args
        payload = kwargs.get("payload", args[0] if args else {})
        assert "timestamp" in payload

    def test_webhook_fired_for_each_supported_type(
        self, upload_service, mock_webhook_client
    ):
        files = [
            make_file("a.pdf", "application/pdf", 1024),
            make_file("b.png", "image/png", 1024),
            make_file("c.jpg", "image/jpeg", 1024),
        ]
        for f in files:
            mock_webhook_client.send.reset_mock()
            upload_service.upload(employee_id="emp-001", file=f)
            mock_webhook_client.send.assert_called_once()


# ---------------------------------------------------------------------------
# 6. Webhook NOT Emitted on Rejection
# ---------------------------------------------------------------------------

class TestWebhookNotEmittedOnRejection:

    def test_webhook_not_called_for_wrong_extension(
        self, upload_service, mock_webhook_client, file_wrong_extension
    ):
        with pytest.raises(ValueError):
            upload_service.upload(employee_id="emp-001", file=file_wrong_extension)
        mock_webhook_client.send.assert_not_called()

    def test_webhook_not_called_for_oversized_file(
        self, upload_service, mock_webhook_client, file_one_byte_over_limit
    ):
        with pytest.raises(ValueError):
            upload_service.upload(employee_id="emp-001", file=file_one_byte_over_limit)
        mock_webhook_client.send.assert_not_called()

    def test_webhook_not_called_for_empty_file(
        self, upload_service, mock_webhook_client, file_empty
    ):
        with pytest.raises(ValueError):
            upload_service.upload(employee_id="emp-001", file=file_empty)
        mock_webhook_client.send.assert_not_called()

    def test_webhook_not_called_for_spoofed_extension(
        self, upload_service, mock_webhook_client, file_spoofed_extension
    ):
        with pytest.raises(ValueError):
            upload_service.upload(employee_id="emp-001", file=file_spoofed_extension)
        mock_webhook_client.send.assert_not_called()

    def test_storage_not_called_for_invalid_file(
        self, upload_service, mock_storage, file_wrong_extension
    ):
        with pytest.raises(ValueError):
            upload_service.upload(employee_id="emp-001", file=file_wrong_extension)
        mock_storage.save.assert_not_called()


# ---------------------------------------------------------------------------
# 7. Webhook Failure Handling
# ---------------------------------------------------------------------------

class TestWebhookFailureHandling:

    def test_upload_succeeds_even_when_webhook_returns_non_200(
        self, upload_service, mock_webhook_client, valid_pdf
    ):
        mock_webhook_client.send.return_value = MagicMock(status_code=503)
        result = upload_service.upload(employee_id="emp-001", file=valid_pdf)
        assert result["success"] is True

    def test_upload_succeeds_even_when_webhook_raises_exception(
        self, upload_service, mock_webhook_client, valid_pdf
    ):
        mock_webhook_client.send.side_effect = ConnectionError("webhook endpoint unreachable")
        result = upload_service.upload(employee_id="emp-001", file=valid_pdf)
        assert result["success"] is True

    def test_webhook_failure_is_logged(
        self, upload_service, mock_webhook_client, valid_pdf
    ):
        mock_webhook_client.send.side_effect = ConnectionError("timeout")
        with patch("onboarding.services.logger") as mock_logger:
            upload_service.upload(employee_id="emp-001", file=valid_pdf)
            mock_logger.error.assert_called_once()


# ---------------------------------------------------------------------------
# 8. Missing / Invalid Input
# ---------------------------------------------------------------------------

class TestMissingOrInvalidInput:

    def test_missing_employee_id_raises_error(self, upload_service, valid_pdf):
        with pytest.raises((ValueError, TypeError)):
            upload_service.upload(employee_id=None, file=valid_pdf)

    def test_empty_employee_id_raises_error(self, upload_service, valid_pdf):
        with pytest.raises(ValueError, match="employee_id"):
            upload_service.upload(employee_id="", file=valid_pdf)

    def test_missing_file_raises_error(self, upload_service):
        with pytest.raises((ValueError, TypeError)):
            upload_service.upload(employee_id="emp-001", file=None)

    def test_missing_filename_raises_error(self, upload_service):
        nameless_file = make_file("", "application/pdf", 1024)
        with pytest.raises(ValueError, match="filename"):
            upload_service.upload(employee_id="emp-001", file=nameless_file)


# ---------------------------------------------------------------------------
# 9. Storage Failure
# ---------------------------------------------------------------------------

class TestStorageFailure:

    def test_storage_failure_raises_error(
        self, upload_service, mock_storage, valid_pdf
    ):
        mock_storage.save.side_effect = IOError("disk full")
        with pytest.raises(IOError):
            upload_service.upload(employee_id="emp-001", file=valid_pdf)

    def test_webhook_not_called_when_storage_fails(
        self, upload_service, mock_storage, mock_webhook_client, valid_pdf
    ):
        mock_storage.save.side_effect = IOError("disk full")
        with pytest.raises(IOError):
            upload_service.upload(employee_id="emp-001", file=valid_pdf)
        mock_webhook_client.send.assert_not_called()


# ---------------------------------------------------------------------------
# 10. Idempotency / Multiple Uploads
# ---------------------------------------------------------------------------

class TestMultipleUploads:

    def test_multiple_uploads_emit_separate_webhook_events(
        self, upload_service, mock_webhook_client, valid_pdf, valid_png
    ):
        upload_service.upload(employee_id="emp-001", file=valid_pdf)
        upload_service.upload(employee_id="emp-001", file=valid_png)
        assert mock_webhook_client.send.call_count == 2

    def test_different_employees_emit_correct_employee_ids_in_webhooks(
        self, upload_service, mock_webhook_client
    ):
        f1 = make_file("a.pdf", "application/pdf", 1024)
        f2 = make_file("b.pdf", "application/pdf", 1024)

        upload_service.upload(employee_id="emp-111", file=f1)
        upload_service.upload(employee_id="emp-222", file=f2)

        calls = mock_webhook_client.send.call_args_list
        payloads = [c[0][0] if c[0] else c[1]["payload"] for c in calls]
        employee_ids = [p["employee_id"] for p in payloads]

        assert "emp-111" in employee_ids
        assert "emp-222" in employee_ids
```

